const raw = items[0]?.json || {};
const payload = raw.payload && typeof raw.payload === 'object' && !Array.isArray(raw.payload) ? raw.payload : raw;
const queueStageRaw = raw.current_stage || raw.queue_stage || raw.stage || payload.current_stage || payload.queue_stage || payload.stage || '';
const queueStage = queueStageRaw === 'Ready for QA' ? 'Waiting for QA' : queueStageRaw;
if (queueStage !== 'Waiting for QA') {
  throw new Error(`AI3 QA scan accepts only the 'Waiting for QA' queue stage. Received: ${queueStageRaw || 'missing'}`);
}
const taskId = payload.task_id || payload.id || raw.task_id || raw.id;
const planLink = payload.plan_link || raw.plan_link;
if (!taskId) throw new Error('Missing task_id');
if (!planLink) throw new Error('Missing plan_link');
return [{
  json: {
    meta: {
      workflow_name: 'AI3_QA_Scan',
      timestamp: new Date().toISOString(),
      trigger_source: raw.trigger_source || 'queue_status_webhook',
      risk_level: raw.risk_level || 'low'
    },
    context: {
      canonical_links: [
        raw.queue_link || '[[04-Tasks/Workflow-Queue|Workflow Queue]]',
        planLink
      ],
      constraints: [
        'Do not approve launch automatically',
        ...(Array.isArray(raw.constraints) ? raw.constraints : [])
      ]
    },
    payload: {
      task_id: taskId,
      plan_link: planLink,
      acceptance_criteria: Array.isArray(payload.acceptance_criteria) ? payload.acceptance_criteria : [],
      implementation_summary: Array.isArray(payload.implementation_summary) ? payload.implementation_summary : [],
      changed_areas: Array.isArray(payload.changed_areas) ? payload.changed_areas : [],
      hotfix: Boolean(payload.hotfix ?? raw.hotfix ?? false)
    }
  }
}];

const item = items[0]?.json || {};
const required = ['agent', 'workflow', 'task_id', 'status', 'result', 'findings', 'follow_up_items', 'escalate_to', 'reason'];
for (const key of required) {
  if (!(key in item)) {
    throw new Error(`Missing required key: ${key}`);
  }
}
const allowedStatus = new Set(['done', 'partial', 'blocked', 'needs_review', 'queued']);
if (!allowedStatus.has(item.status)) {
  throw new Error(`Invalid status: ${item.status}`);
}
const allowedResult = new Set(['pass', 'fail', 'needs_review']);
if (!allowedResult.has(item.result)) {
  throw new Error(`Invalid result: ${item.result}`);
}
const allowedEscalation = new Set(['none', 'AI-1', 'AI-2', 'AI-3', 'AI-5', 'AI-6', 'AI-7', 'AI-8', 'AI-9', 'AI-10', 'AI-11', 'Owner']);
if (!allowedEscalation.has(item.escalate_to)) {
  throw new Error(`Invalid escalate_to: ${item.escalate_to}`);
}
item.execution_action = item.result === 'pass' && item.escalate_to === 'none' ? 'write_qa_scan_and_move_queue' : 'create_follow_up_or_escalation';
item.queue_stage = 'Waiting for QA';
return [{ json: item }];
